from flask import Flask, redirect, url_for, request
import requests

app = Flask(__name__)
CLIENT_ID = 'your_client_id'
REDIRECT_URI = 'http://localhost:5000/callback'

@app.route('/')
def index():
    authorization_url = f'https://your-oidc-provider.com/auth/realms/{YOUR_REALM}/protocol/openid-connect/auth?client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&scope=openid&response_type=id_token'
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    token_response = requests.post(
        'https://your-oidc-provider.com/auth/realms/{YOUR_REALM}/protocol/openid-connect/token',
        data={
            'client_id': CLIENT_ID,
            'redirect_uri': REDIRECT_URI,
            'code': request.args.get('code'),
            'grant_type': 'authorization_code'
        }
    )
    id_token = token_response.json().get('id_token')
    return f'ID Token: {id_token}'

if __name__ == '__main__':
    app.run(debug=True)